517:         uint collAmt = IPosManager(POS_MANAGER).getCollAmt(initPosId, marginPos.collPool);
518:         _require(_collAmt <= collAmt, Errors.INPUT_TOO_HIGH);
519: 
520:         order.triggerPrice_e36 = _triggerPrice_e36;
